import { Injectable } from '@angular/core';
import { map, Observable } from 'rxjs';
import { CommonHttpModule } from '../../providers/commonHttpModule';
import { DashboardRequest, DashboardTableRequest } from './dashboard.component.model';

@Injectable({
    providedIn: 'root'
})
export class DashboardService {
    constructor(private http: CommonHttpModule) { }


    getDashboardData(request: DashboardRequest): Observable<any> {
        return this.http.post("dashboard", request).pipe(
            map((response) => {
                return response;
            })
        )
    }

    getDashboardTableData(request: DashboardTableRequest): Observable<any> {
        return this.http.post("dashboard-table", request).pipe(
            map((response) => {
                return response;
            })
        )
    }

    getVesselListData(clientId: string | null = null): Observable<any> {
        return this.http.post("dashboard-filter-data", { client_id: clientId }).pipe(
            map((response) => {
                return response;
            })
        )
    }

}
